#include <iostream>
#include <vector>
using namespace std;

template<typename T, int MAX = 100>
class Stack {
private:
    vector<T> elements;
    int top;

public:
    Stack() : top(-1) {}

    bool push(const T& item) {
        if (top >= MAX - 1) {
            cout << "Stack Overflow!\n";
            return false;
        }
        elements.push_back(item);
        top++;
        return true;
    }

    bool pop() {
        if (top < 0) {
            cout << "Stack Underflow!\n";
            return false;
        }
        elements.pop_back();
        top--;
        return true;
    }

    T& peek() {
        if (top < 0) throw "Stack is empty";
        return elements[top];
    }

    bool isEmpty() { return top == -1; }

    void display() {
        cout << "Stack elements: ";
        for (int i = 0; i <= top; i++)
            cout << elements[i] << " ";
        cout << endl;
    }
};

int main() {
    Stack<int> intStack;
    intStack.push(10);
    intStack.push(20);
    intStack.display();

    Stack<string> strStack;
    strStack.push("Hello");
    strStack.push("World");
    strStack.display();

    return 0;
}

#include <iostream>
#include <cstring>
using namespace std;

// Primary Function Template
template<typename T>
T maximum(T a, T b) {
    return (a > b) ? a : b;
}

// Full Specialization for char* (C-style strings)
template<>
char* maximum<char*>(char* a, char* b) {
    return (strcmp(a, b) > 0) ? a : b;
}

// Specialization for const char*
template<>
const char* maximum<const char*>(const char* a, const char* b) {
    return (strcmp(a, b) > 0) ? a : b;
}

int main() {
    // Works with regular types
    int x = 5, y = 8;
    cout << "Max int: " << maximum(x, y) << endl;

    // Uses specialized version for C-strings
    const char* s1 = "Apple";
    const char* s2 = "Banana";
    cout << "Max string: " << maximum(s1, s2) << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Primary Class Template
template<typename T, int size>
class Array {
private:
    T arr[size];
public:
    void display() {
        cout << "Primary Array template" << endl;
    }
};

// Partial Specialization for pointer types
template<typename T, int size>
class Array<T*, size> {
private:
    T* arr[size];
public:
    void display() {
        cout << "Partial specialization for pointer types" << endl;
    }
};

// Partial Specialization for arrays with size 10
template<typename T>
class Array<T, 10> {
private:
    T arr[10];
public:
    void display() {
        cout << "Partial specialization for size 10 arrays" << endl;
    }
};

int main() {
    Array<int, 5> a1;          // Uses primary template
    a1.display();

    Array<int*, 5> a2;         // Uses pointer specialization
    a2.display();

    Array<int, 10> a3;          // Uses size 10 specialization
    a3.display();

    return 0;
}
